function distanceLimitedPathsExist(n, edgeList, queries) {
    edgeList.sort((a, b) => a[2] - b[2]);
    queries = queries.map((query, idx) => [...query, idx]).sort((a, b) => a[2] - b[2]);

    function find(x, parent) {
        if (x !== parent[x]) {
            parent[x] = find(parent[x], parent);
        }
        return parent[x];
    }

    const parent = Array.from({ length: n }, (_, idx) => idx);
    const res = new Array(queries.length).fill(false);
    let idx = 0;

    for (const query of queries) {
        const [p, q, limit, queryId] = query;
        while (idx < edgeList.length && edgeList[idx][2] < limit) {
            const [u, v] = edgeList[idx];
            const [ru, rv] = [find(u, parent), find(v, parent)];
            if (ru !== rv) {
                parent[ru] = rv;
            }
            idx++;
        }
        res[queryId] = find(p, parent) === find(q, parent);
    }

    return res;
}
```

    The algorithm starts by sorting `edgeList` by edge distance and `queries` by limit. We then use a disjoint set data structure (implemented using the `parent` list) to keep track of connected components, and we initialize each node to be its own parent.

The main idea of the algorithm is to iterate through the sorted queries and process those edges (in the edge list) with distance smaller than the query limit. We do this by iterating through the `queries`, and within each iteration, we iterate through the `edgeList` for all edges with distance less than the query limit, and union the connected nodes in the parent.

After processing the edges, we then check if the two nodes in the current query, `p` and `q`, are in the same connected component. If they are, it means that there exists a path between them with edge distances less than the query limit. We store this result in the answer array.

Finally, we return the answer array containing boolean values for each query.

